import React, { useState, useEffect } from 'react';
import { ShoppingCart, MapPin, Search, Globe } from 'lucide-react';

const PanelCliente = () => {
  const [todasLasOfertas, setTodasLasOfertas] = useState([]);
  const [ofertasFiltradas, setOfertasFiltradas] = useState([]);
  const [busqueda, setBusqueda] = useState('');
  
  const [provinciaSel, setProvinciaSel] = useState('Tucumán');
  const [ciudadSel, setCiudadSel] = useState('Todas');
  const [zonaSel, setZonaSel] = useState('Todas las zonas');

  const provinciasArgentina = ['Buenos Aires', 'CABA', 'Catamarca', 'Chaco', 'Chubut', 'Córdoba', 'Corrientes', 'Entre Ríos', 'Formosa', 'Jujuy', 'La Pampa', 'La Rioja', 'Mendoza', 'Misiones', 'Neuquén', 'Río Negro', 'Salta', 'San Juan', 'San Luis', 'Santa Cruz', 'Santa Fe', 'Santiago del Estero', 'Tierra del Fuego', 'Tucumán'].sort();

  const ciudadesPorProvincia = {
    'Tucumán': ['San Miguel de Tucumán', 'Yerba Buena', 'Tafí Viejo', 'Concepción'],
    'Salta': ['Salta Capital', 'Cafayate'],
    'Buenos Aires': ['La Plata', 'Mar del Plata'],
  };

  useEffect(() => {
    const locales = JSON.parse(localStorage.getItem('mis-locales') || "[]");
    let acumulador = [];

    locales.forEach(local => {
      const ofertasLocal = JSON.parse(localStorage.getItem(`ofertas-local-${local.id}`) || "[]");
      acumulador = [...acumulador, ...ofertasLocal.map(o => ({
        ...o,
        nombreLocal: local.nombre,
        zona: o.zona || local.zona || 'Centro',
        ciudad: local.ciudad || 'San Miguel de Tucumán',
        provincia: local.provincia || 'Tucumán'
      }))];
    });

    // Inyectamos datos de prueba si está vacío para que veas que el filtro funciona
    if (acumulador.length === 0) {
      acumulador = [
        { id: 1, producto: 'Aceite Girasol', precioNuevo: 1200, precioViejo: 1800, nombreLocal: 'Super Tuc', zona: 'Barrio Norte', ciudad: 'San Miguel de Tucumán', provincia: 'Tucumán' },
        { id: 2, producto: 'Leche Entera', precioNuevo: 800, precioViejo: 1100, nombreLocal: 'Express', zona: 'Yerba Buena', ciudad: 'Yerba Buena', provincia: 'Tucumán' }
      ];
    }
    setTodasLasOfertas(acumulador);
  }, []);

  // LÓGICA DE FILTRADO REAL
  useEffect(() => {
    const resultado = todasLasOfertas.filter(o => {
      const matchBusqueda = o.producto.toLowerCase().includes(busqueda.toLowerCase());
      const matchProvincia = o.provincia === provinciaSel;
      const matchCiudad = ciudadSel === 'Todas' || o.ciudad === ciudadSel;
      const matchZona = zonaSel === 'Todas las zonas' || o.zona === zonaSel;
      
      return matchBusqueda && matchProvincia && matchCiudad && matchZona;
    });
    setOfertasFiltradas(resultado);
  }, [busqueda, provinciaSel, ciudadSel, zonaSel, todasLasOfertas]);

  // Generar botones de zona basados en las ofertas que SÍ existen
  const zonasExistentes = ['Todas las zonas', ...new Set(
    todasLasOfertas
      .filter(o => o.provincia === provinciaSel && (ciudadSel === 'Todas' || o.ciudad === ciudadSel))
      .map(o => o.zona)
  )];

  return (
    <div style={{ background: '#f4f7f6', minHeight: '100vh', fontFamily: 'sans-serif' }}>
      <div style={navUbicacion}>
        <div style={contenedorUbi}>
          <div style={ubiGroup}>
            <Globe size={18} color="#e67e22" />
            <div style={selectBox}>
              <label style={miniLabel}>Provincia</label>
              <select value={provinciaSel} onChange={(e) => { setProvinciaSel(e.target.value); setCiudadSel('Todas'); setZonaSel('Todas las zonas'); }} style={selectEstilo}>
                {provinciasArgentina.map(p => <option key={p} value={p}>{p}</option>)}
              </select>
            </div>
          </div>
          <div style={divisorV} />
          <div style={ubiGroup}>
            <MapPin size={18} color="#e67e22" />
            <div style={selectBox}>
              <label style={miniLabel}>Ciudad</label>
              <select value={ciudadSel} onChange={(e) => { setCiudadSel(e.target.value); setZonaSel('Todas las zonas'); }} style={selectEstilo}>
                <option value="Todas">Todas las ciudades</option>
                {(ciudadesPorProvincia[provinciaSel] || []).map(c => <option key={c} value={c}>{c}</option>)}
              </select>
            </div>
          </div>
        </div>

        <div style={zonaWrapper}>
          <div style={zonaScroll}>
            {zonasExistentes.map(z => (
              <button key={z} onClick={() => setZonaSel(z)} style={zonaSel === z ? zonaBtnActive : zonaBtn}>
                {z}
              </button>
            ))}
          </div>
        </div>
      </div>

      <div style={{ padding: '20px 5%' }}>
        <div style={searchContainer}>
          <Search size={20} color="#94a3b8" />
          <input type="text" placeholder="Buscar productos..." style={inputBusqueda} onChange={(e) => setBusqueda(e.target.value)} />
        </div>

        <h3 style={{ margin: '20px 0', color: '#1e293b' }}>
          {zonaSel === 'Todas las zonas' ? `Ofertas en ${ciudadSel === 'Todas' ? provinciaSel : ciudadSel}` : `Ofertas en ${zonaSel}`}
        </h3>
        
        <div style={gridPro}>
          {ofertasFiltradas.map(o => (
            <div key={o.id} style={cardPro}>
              <div style={ahorroBadge}>-{Math.round(((o.precioViejo - o.precioNuevo)/o.precioViejo)*100)}%</div>
              <div style={cuerpoCard}>
                <p style={localTag}>{o.nombreLocal} • {o.zona}</p>
                <h4 style={prodTitle}>{o.producto}</h4>
                <div style={priceContainer}>
                  <span style={priceMain}>${o.precioNuevo}</span>
                  <span style={priceOff}>${o.precioViejo}</span>
                </div>
                <button style={btnComprarPro}><ShoppingCart size={18} /> Reservar</button>
              </div>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
};

const navUbicacion = { background: 'white', padding: '15px 5%', borderBottom: '1px solid #e2e8f0', position: 'sticky', top: 0, zIndex: 1000 };
const contenedorUbi = { display: 'flex', alignItems: 'center', background: '#f8fafc', borderRadius: '12px', padding: '10px 15px', marginBottom: '15px' };
const ubiGroup = { display: 'flex', alignItems: 'center', gap: '10px', flex: 1 };
const selectBox = { display: 'flex', flexDirection: 'column' };
const miniLabel = { fontSize: '0.6rem', color: '#94a3b8', fontWeight: 'bold' };
const selectEstilo = { border: 'none', background: 'transparent', fontSize: '0.9rem', fontWeight: 'bold', outline: 'none', cursor: 'pointer' };
const divisorV = { width: '1px', height: '25px', background: '#e2e8f0', margin: '0 15px' };
